use crate::collider::ColliderHandle;
use crate::math::Vec2;

/// Persisted SAT / clipping state for polygon–polygon (and cuboid–cuboid) pairs.
/// Used next frame to reduce axis flipping and warm-start churn at corners.
#[derive(Clone, Copy, Debug)]
pub struct PolyPolySatHint {
    /// Contact normal, normalized, pointing from collider A toward collider B.
    pub axis_from_a_to_b: Vec2,
    /// Overlap depth along `axis_from_a_to_b` (MTD magnitude).
    pub mtd: f32,
    /// Whether shape A was the reference polygon for SAT clipping (`use_a_as_ref` after normal flip).
    pub use_first_shape_as_reference: bool,
}

#[derive(Clone, Debug)]
pub struct ContactPoint {
    pub local_a: Vec2,
    pub local_b: Vec2,
    pub penetration: f32,
    pub impulse_id: u32,
    /// Whether this contact is new this frame (for restitution gating)
    pub is_new: bool,
}

#[derive(Clone, Debug)]
pub struct ContactManifold {
    pub normal: Vec2,
    pub contacts: Vec<ContactPoint>,
    /// Set only for polygon–polygon / OBB–OBB manifolds; drives narrowphase hysteresis.
    pub poly_poly_sat: Option<PolyPolySatHint>,
}

impl ContactManifold {
    pub fn new(normal: Vec2) -> Self {
        Self {
            normal,
            contacts: Vec::new(),
            poly_poly_sat: None,
        }
    }

    /// Swap A/B roles so the same geometric contact is expressed with the other collider as reference.
    pub fn flipped_across_bodies(mut self) -> Self {
        self.normal = -self.normal;
        self.poly_poly_sat = None;
        for cp in &mut self.contacts {
            std::mem::swap(&mut cp.local_a, &mut cp.local_b);
        }
        self
    }

    pub fn with_point(mut self, local_a: Vec2, local_b: Vec2, penetration: f32) -> Self {
        self.contacts.push(ContactPoint {
            local_a,
            local_b,
            penetration,
            impulse_id: self.contacts.len() as u32,
            is_new: true,
        });
        self
    }

    pub fn max_penetration(&self) -> f32 {
        self.contacts
            .iter()
            .map(|c| c.penetration)
            .fold(0.0, f32::max)
    }
}

#[derive(Clone, Debug)]
pub struct ContactPair {
    pub collider_a: ColliderHandle,
    pub collider_b: ColliderHandle,
    pub manifold: ContactManifold,
    /// Last frame’s poly–poly SAT hint for `(collider_a, collider_b)` order.
    pub last_poly_sat: Option<PolyPolySatHint>,
}

impl ContactPair {
    pub fn new(
        collider_a: ColliderHandle,
        collider_b: ColliderHandle,
        manifold: ContactManifold,
    ) -> Self {
        let last_poly_sat = manifold.poly_poly_sat;
        Self {
            collider_a,
            collider_b,
            manifold,
            last_poly_sat,
        }
    }
}

pub enum ContactEvent {
    Started(ColliderHandle, ColliderHandle),
    Stopped(ColliderHandle, ColliderHandle),
}

pub struct ContactTracker {
    pairs: std::collections::HashMap<(ColliderHandle, ColliderHandle), ContactPair>,
    active_pairs: Vec<(ColliderHandle, ColliderHandle)>,
    pub events: Vec<ContactEvent>,
}

impl ContactTracker {
    pub fn new() -> Self {
        Self {
            pairs: std::collections::HashMap::new(),
            active_pairs: Vec::new(),
            events: Vec::new(),
        }
    }

    pub fn update(
        &mut self,
        new_manifolds: Vec<(ColliderHandle, ColliderHandle, ContactManifold)>,
    ) {
        self.active_pairs.clear();
        self.events.clear();

        // Track which old pairs are still active
        let mut still_active = std::collections::HashSet::new();

        for (ca, cb, mut manifold) in new_manifolds {
            let key = (ca, cb);
            still_active.insert(key);
            self.active_pairs.push(key);

            if let Some(pair) = self.pairs.get_mut(&key) {
                // Update is_new flags on the new manifold contacts
                let old_normal = pair.manifold.normal;
                let old_contacts = &pair.manifold.contacts;
                let new_normal = manifold.normal;
                let new_len_one = manifold.contacts.len() == 1;
                let old_len_one = old_contacts.len() == 1;
                for new_c in &mut manifold.contacts {
                    let mut found = false;
                    for old_c in old_contacts {
                        let dxa = new_c.local_a.x - old_c.local_a.x;
                        let dya = new_c.local_a.y - old_c.local_a.y;
                        let dist_a_sq = dxa * dxa + dya * dya;
                        let dxb = new_c.local_b.x - old_c.local_b.x;
                        let dyb = new_c.local_b.y - old_c.local_b.y;
                        let dist_b_sq = dxb * dxb + dyb * dyb;
                        if dist_a_sq < 0.01 && dist_b_sq < 0.01 {
                            new_c.is_new = false;
                            found = true;
                            break;
                        }
                    }
                    // Single-contact manifolds (circle–floor, etc.): the anchor on a spinning disk
                    // moves in body space even when the world contact is steady. If we always mark
                    // those as new, resting bodies never sleep and friction impulses never warm-start.
                    if !found
                        && new_len_one
                        && old_len_one
                        && old_normal.dot(new_normal) >= 0.995
                    {
                        let old_p = old_contacts[0].penetration.max(1e-6);
                        let pen_delta = (new_c.penetration - old_contacts[0].penetration).abs();
                        if pen_delta < old_p * 0.65 {
                            new_c.is_new = false;
                            found = true;
                        }
                    }
                    if !found {
                        new_c.is_new = true;
                    }
                }

                pair.manifold = manifold;
                pair.last_poly_sat = pair.manifold.poly_poly_sat;
            } else {
                // New contact
                self.events.push(ContactEvent::Started(ca, cb));
                self.pairs.insert(key, ContactPair::new(ca, cb, manifold));
            }
        }

        // Remove pairs that are no longer active
        let old_keys: Vec<_> = self.pairs.keys().copied().collect();
        for key in old_keys {
            if !still_active.contains(&key) {
                self.events.push(ContactEvent::Stopped(key.0, key.1));
                self.pairs.remove(&key);
            }
        }
    }

    pub fn pairs(&self) -> impl Iterator<Item = &ContactPair> {
        self.pairs.values()
    }

    pub fn pairs_mut(&mut self) -> impl Iterator<Item = &mut ContactPair> {
        self.pairs.values_mut()
    }

    pub fn pair_count(&self) -> usize {
        self.pairs.len()
    }

    /// Hysteresis hint for polygon–polygon narrowphase (`collider_a`, `collider_b` order).
    pub fn poly_sat_hint(
        &self,
        ca: ColliderHandle,
        cb: ColliderHandle,
    ) -> Option<PolyPolySatHint> {
        self.pairs.get(&(ca, cb)).and_then(|p| p.last_poly_sat)
    }

    pub fn clear(&mut self) {
        self.pairs.clear();
        self.active_pairs.clear();
        self.events.clear();
    }
}

impl Default for ContactTracker {
    fn default() -> Self {
        Self::new()
    }
}
